"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[362],{6362:function(e,t,a){a.r(t),a.d(t,{lessonCatalog:function(){return i}});let i={levels:["Beginner","Intermediate","Advanced","Pro"],lessons:[{id:"beg-01",level:"Beginner",title:"How the Stock Market Actually Works",type:"story",durationMinutes:4,focus:["market","canslim"],content:["The market is a live auction for future earnings power. Prices move because expectations change, not because a company is simply popular.","In growth trading, earnings momentum plus institutional demand matters more than low valuation. Think in probabilities, not certainties."],example:"Two stocks beat earnings, but only one guides higher and breaks out on heavy volume. Institutions usually pay for improving expectations, not static quality.",keyTakeaways:["Price reflects expectations.","Volume reveals conviction.","Growth momentum beats cheap laggards."],quiz:[{id:"q1",question:"Best definition of daily stock price?",options:["Random number","Live auction of expectations","Only social mood","Pure accounting output"],correctIndex:1,explanation:"Market pricing constantly updates expected future cash flows and risk."}],answers:["Live auction of expectations."]},{id:"beg-02",level:"Beginner",title:"Why Stocks Move: Earnings, Rates, and Positioning",type:"chart",durationMinutes:5,focus:["market","news","canslim"],content:["Large moves usually happen when earnings expectations and liquidity conditions shift together.","Strong company data can still fail if market risk appetite is weak. Always blend stock story with market context."],example:"A stock beats EPS but guidance is soft while yields jump. It opens strong then sells off as institutions de-risk growth exposure.",keyTakeaways:["Earnings revisions matter.","Macro regime matters.","Context can overpower headlines."],quiz:[{id:"q1",question:"Why can a good report fail?",options:["Chart glitch","No one read it","Macro/positioning overruled it","Earnings never matter"],correctIndex:2,explanation:"The tape reflects all forces, including liquidity and positioning."}],answers:["Macro and positioning can override good earnings."]},{id:"beg-03",level:"Beginner",title:"Beginner Mistakes That Blow Up Accounts",type:"decision-lab",durationMinutes:6,focus:["portfolio","market"],content:["The biggest errors are process errors: no stop loss, oversized positions, revenge trades, and averaging down losers.","Professional behavior means defining invalidation before entry. Hope is not a risk policy."],example:"Trader A cuts at -1R and survives ten losses. Trader B averages down with no stop and one bad trade wipes months of progress.",keyTakeaways:["Define risk first.","Never let one trade dominate account risk.","Small losses are normal business costs."],quiz:[{id:"q1",question:"Most dangerous behavior?",options:["Taking planned small losses","Reducing size in drawdown","Averaging down without a stop","Waiting for confirmation"],correctIndex:2,explanation:"Unbounded downside destroys compounding."}],answers:["Averaging down without a stop."]},{id:"beg-04",level:"Beginner",title:"Candles and Volume Without Confusion",type:"chart",durationMinutes:5,focus:["breakouts","market"],content:["Candles show session control; volume shows commitment. A strong close on high volume is more meaningful than a random green bar on low volume.","Use context: breakout quality is highest when price clears resistance and volume expands materially."],example:"A stock clears resistance with 1.7x average volume and closes near highs; that is stronger than an intraday spike that fades by close.",keyTakeaways:["Close location matters.","Volume confirms price intent.","Low-volume pullbacks can be constructive."],quiz:[{id:"q1",question:"Which signal is strongest?",options:["Low-volume breakout","High-volume breakout and strong close","No-volume inside day","Gap down on heavy volume"],correctIndex:1,explanation:"Institutional footprints typically appear as strong breakout volume."}],answers:["High-volume breakout with strong close."]},{id:"beg-05",level:"Beginner",title:"Support, Resistance, and Market Memory",type:"story",durationMinutes:4,focus:["breakouts","market"],content:["Support and resistance are zones where market participants remember pain and opportunity.","Resistance breaks only when demand absorbs trapped supply. That is why volume matters at pivots."],example:"After three failed attempts at 120, a stock finally closes above 120 on the highest volume in six weeks, signaling absorption of supply.",keyTakeaways:["Levels represent positioning, not magic.","Repeated tests increase importance.","Volume helps validate breaks."],quiz:[{id:"q1",question:"Why is resistance real?",options:["Indicator says so","Trapped holders often sell there","Because round numbers always work","No reason"],correctIndex:1,explanation:"Prior buyers often use retests to exit, creating supply."}],answers:["Trapped holders create supply near resistance."]},{id:"beg-06",level:"Beginner",title:"Daily Routine for Consistent Trading",type:"playbook",durationMinutes:3,focus:["portfolio","canslim","breakouts"],content:["A simple routine creates consistency: pre-market context, intraday execution discipline, post-market review.","Checklist-driven decisions reduce emotional trades and improve repeatability."],example:"Evening review identifies weak breadth and failed breakouts, so next day position sizes are reduced before entries are considered.",keyTakeaways:["Routine beats intensity.","Checklist reduces impulse decisions.","Review loop sharpens edge."],quiz:[{id:"q1",question:"First step each day?",options:["Open social feed","Check market regime","Buy top gainer","Ignore prior day"],correctIndex:1,explanation:"Context should always come before entries."}],answers:["Check market regime first."]},{id:"beg-07",level:"Beginner",title:"1R Position Sizing Fundamentals",type:"simulation",durationMinutes:5,focus:["portfolio"],content:["Define R as maximum loss per trade. With a fixed R, your results become comparable across setups.","Position size should come from risk per share and account risk, not from conviction alone."],example:"If account risk is 200 and risk/share is 4, size is 50 shares. This keeps losses controlled and outcomes measurable.",keyTakeaways:["Size from risk, not emotion.","Track performance in R-multiples.","Avoid oversized conviction trades."],quiz:[{id:"q1",question:"If 1R is 150 and risk/share is 3, size is:",options:["30","40","50","60"],correctIndex:2,explanation:"150 divided by 3 equals 50 shares."}],answers:["50 shares."]},{id:"beg-08",level:"Beginner",title:"When Not to Trade",type:"case-study",durationMinutes:3,focus:["market","portfolio"],content:["Professional traders often make money by waiting. In weak market regimes, preserving capital beats forcing setups.","Cash is a strategic position that protects both financial and mental capital."],example:"After repeated breakout failures and index weakness, exposure is cut to cash until a valid follow-through day appears.",keyTakeaways:["No-trade periods are part of edge.","Cash preserves optionality.","Wait for favorable conditions."],quiz:[{id:"q1",question:"Best action during broad breakout failures?",options:["Trade more","Increase leverage","Reduce exposure and wait","Ignore market"],correctIndex:2,explanation:"Regime-aware patience improves long-term performance."}],answers:["Reduce exposure and wait for confirmation."]},{id:"int-01",level:"Intermediate",title:"CANSLIM End-to-End Framework",type:"playbook",durationMinutes:12,focus:["canslim"],content:["CANSLIM ranks growth quality by combining fundamentals, technical demand, sponsorship, and market regime.","Treat the score as a probability tool. High scores improve odds, but market direction still controls exposure."],example:"A stock with strong C/A/L metrics still gets risk-adjusted lower in a correction because M is weak.",keyTakeaways:["CANSLIM is multi-factor.","M controls aggressiveness.","Score guides prioritization."],quiz:[{id:"q1",question:"Which letter controls market regime risk?",options:["C","A","I","M"],correctIndex:3,explanation:"M determines whether conditions support offensive sizing."}],answers:["M."]},{id:"int-02",level:"Intermediate",title:"C: Quarterly Earnings Acceleration",type:"case-study",durationMinutes:11,focus:["canslim","news"],content:["Quarterly EPS growth should be strong and ideally accelerating. Revenue and margin trend validate earnings quality.","Look beyond one beat: estimate revisions and guidance quality often determine persistence."],example:"EPS rises from +28% to +51% to +79% while revenue growth also accelerates. Institutional demand typically strengthens.",keyTakeaways:["Acceleration matters.","Revenue confirms EPS quality.","Guidance and revisions matter."],quiz:[{id:"q1",question:"Best C signal?",options:["EPS up, sales flat","EPS and sales accelerating","EPS down, margin up","No guidance"],correctIndex:1,explanation:"Broad acceleration is more robust than isolated EPS changes."}],answers:["EPS and sales accelerating."]},{id:"int-03",level:"Intermediate",title:"A: Annual Earnings Durability",type:"chart",durationMinutes:10,focus:["canslim"],content:["A evaluates multi-year compounding, not one hot quarter. Stable EPS growth and strong ROE support higher conviction.","Inconsistent histories can trade tactically, but usually deserve smaller size and tighter risk."],example:"A company with 5-year EPS CAGR above 25% and ROE above 20% tends to attract quality institutional capital.",keyTakeaways:["Seek consistency over spikes.","ROE and margin trend matter.","Durability improves conviction."],quiz:[{id:"q1",question:"Why does annual consistency matter?",options:["Looks cleaner","Signals repeatable execution","Eliminates losses","Replaces stop losses"],correctIndex:1,explanation:"Consistency helps forecast future business quality."}],answers:["It signals repeatable execution."]},{id:"int-04",level:"Intermediate",title:"N: Finding Real Catalysts",type:"story",durationMinutes:8,focus:["canslim","news","breakouts"],content:["N captures change: product launches, management shifts, strategic expansion, or technical new highs.","A useful filter is whether the catalyst can plausibly raise future earnings and demand from institutions."],example:"A med-tech device approval lifts two-year guidance and drives a 52-week high breakout with heavy volume.",keyTakeaways:["Catalysts must be measurable.","New highs can signal re-rating.","Narrative alone is weak."],quiz:[{id:"q1",question:"Strongest N example?",options:["Vague PR update","Guidance-raising catalyst plus breakout","Falling to new lows","Old product refresh"],correctIndex:1,explanation:"Catalyst plus demand confirmation is the strongest combination."}],answers:["Guidance-raising catalyst plus breakout."]},{id:"int-05",level:"Intermediate",title:"S: Supply and Demand in Daily Tape",type:"chart",durationMinutes:9,focus:["canslim","breakouts"],content:["Accumulation appears when up days carry stronger volume than pullbacks. Distribution appears when declines print heavy volume repeatedly.","Lower float can amplify upside but also downside; liquidity quality should influence position sizing."],example:"A stock posts repeated above-average up-volume days and quiet pullbacks, then breaks out with conviction.",keyTakeaways:["Volume asymmetry matters.","Distribution clusters are warnings.","Liquidity affects risk."],quiz:[{id:"q1",question:"Best sign of accumulation?",options:["Heavy down-volume days","Up days with stronger volume than pullbacks","Flat volume forever","Only low price"],correctIndex:1,explanation:"Demand dominance usually shows through stronger upside volume."}],answers:["Up days with stronger volume."]},{id:"int-06",level:"Intermediate",title:"L: Leader vs Laggard Selection",type:"simulation",durationMinutes:9,focus:["canslim","market"],content:["Leaders with high relative strength tend to recover faster and break out earlier after pullbacks.","Laggards can look cheap for long periods; underperformance is often a warning, not an opportunity."],example:"RS 92 stock reclaims key averages quickly while RS 58 peer remains below 50-day for weeks.",keyTakeaways:["Prefer RS 80+, ideally 90+.","Leadership persistence is a real edge.","Cheap laggards are often traps."],quiz:[{id:"q1",question:"Preferred CANSLIM profile?",options:["RS 45 turnaround","RS 90+ in leading group","Lowest PE only","Most volatile penny stock"],correctIndex:1,explanation:"CANSLIM prioritizes proven relative leadership."}],answers:["RS 90+ in a leading group."]},{id:"int-07",level:"Intermediate",title:"I: Institutional Sponsorship Quality",type:"case-study",durationMinutes:8,focus:["canslim"],content:["Rising sponsorship from credible funds supports trend durability, but complete crowding can limit marginal demand.","Ownership trend should align with constructive price/volume action."],example:"Fund ownership rises for three quarters while price holds above 50-day and earnings accelerate.",keyTakeaways:["Quality of sponsorship matters.","Rising ownership is a tailwind.","Avoid over-crowded slow growers."],quiz:[{id:"q1",question:"Best sponsorship profile?",options:["No institutions","Rising high-quality funds with room left","Fully saturated and slowing","Unknown ownership"],correctIndex:1,explanation:"Fresh sponsorship helps support continued demand."}],answers:["Rising quality sponsorship with room for more."]},{id:"int-08",level:"Intermediate",title:"M: Market Direction and Exposure Rules",type:"playbook",durationMinutes:10,focus:["market","portfolio","canslim"],content:["Market direction controls your offensive or defensive stance. In corrections, preserve capital; in confirmed uptrends, scale exposure with evidence.","Use objective signals: index position vs moving averages, breadth, and breakout success rate."],example:"After breadth improves and indices reclaim key averages, exposure is increased from 25% to 45% in steps instead of all at once.",keyTakeaways:["Let market quality set risk budget.","Scale in gradually.","Breakout failure rate is a key regime signal."],quiz:[{id:"q1",question:"When market weakens, what should change first?",options:["Storytelling","Risk exposure","Number of watchlist names","Chart color theme"],correctIndex:1,explanation:"Exposure is the fastest and most effective control lever."}],answers:["Risk exposure."]},{id:"adv-01",level:"Advanced",title:"Cup with Handle: High-Quality Setup Rules",type:"chart",durationMinutes:14,focus:["breakouts","canslim"],content:["A quality cup-with-handle usually has 12-33% depth and enough time to form a rounded base. The handle should stay in the upper half and remain relatively shallow.","Breakout validation requires strong close and decisive volume expansion. V-shaped recoveries without consolidation are higher risk."],example:"Stock corrects 24% over 10 weeks, forms tight upper-half handle, then breaks pivot on 1.8x average volume.",keyTakeaways:["Respect structure quality.","Upper-half handle is key.","Volume confirms pivot break."],quiz:[{id:"q1",question:"Healthiest handle profile?",options:["Deep lower-half handle","Upper-half tight handle with volume dry-up","No handle after V move","Heavy distribution in handle"],correctIndex:1,explanation:"Controlled handles suggest limited supply before breakout."}],answers:["Upper-half tight handle with volume dry-up."]},{id:"adv-02",level:"Advanced",title:"Double Bottom: Pivot Timing",type:"simulation",durationMinutes:12,focus:["breakouts"],content:["The official double-bottom pivot is the middle peak of the W pattern plus a small buffer.","Early entries near second low can work but carry higher failure probability than confirmed pivot breaks."],example:"W pattern forms 80-92-78; correct pivot is 92, not the 78 rebound.",keyTakeaways:["Middle-peak pivot defines trigger.","Confirmation beats anticipation.","Watch close quality near pivot."],quiz:[{id:"q1",question:"Official buy point in double bottom?",options:["Second low","Middle peak + buffer","First low","Any green candle"],correctIndex:1,explanation:"Middle-peak resistance is the key level institutions must clear."}],answers:["Middle peak plus buffer."]},{id:"adv-03",level:"Advanced",title:"Flat Base Precision",type:"chart",durationMinutes:10,focus:["breakouts"],content:["Flat bases are tight consolidations, typically 5+ weeks and shallow depth. Tightness is a sign of sponsorship control.","Entries should stay within buy-zone discipline. Chasing extended moves degrades reward-to-risk."],example:"Stock ranges tightly for six weeks, then clears base high with strong volume and closes near day high.",keyTakeaways:["Tightness is a quality signal.","Respect buy zone.","RS line behavior improves confidence."],quiz:[{id:"q1",question:"Flat-base strength sign?",options:["Wide swings","Tight weekly closes","Repeated heavy down-volume breaks","No trend context"],correctIndex:1,explanation:"Orderly tight action often indicates controlled sponsorship."}],answers:["Tight and orderly consolidation."]},{id:"adv-04",level:"Advanced",title:"Ascending Base and Stair-Step Demand",type:"case-study",durationMinutes:11,focus:["breakouts","canslim"],content:["Ascending bases show repeated shallow consolidations at progressively higher levels, often in very strong leaders.","Because momentum is elevated, strict stop rules are essential if breakout momentum fades."],example:"Three pullbacks of 8%, 7%, and 6% each resolve higher before final breakout with volume confirmation.",keyTakeaways:["Stair-step structure signals persistent demand.","Momentum needs discipline.","Volume still validates entry."],quiz:[{id:"q1",question:"Core pattern trait of ascending base?",options:["One deep correction","Three shallow pullbacks in sequence","No pullbacks ever","Only gap downs"],correctIndex:1,explanation:"The repeated shallow stair-step structure defines the pattern."}],answers:["Three shallow pullbacks in sequence."]},{id:"adv-05",level:"Advanced",title:"IPO Base Execution",type:"story",durationMinutes:10,focus:["breakouts","news"],content:["IPO names often need time to absorb early supply. Wait for a clear base before committing size.","Strong IPO-base breakouts usually combine structure, fresh fundamentals, and volume expansion."],example:"New listing consolidates for seven weeks after early volatility, then breaks above base high after first strong earnings report.",keyTakeaways:["Patience improves IPO timing.","Require structure and volume.","Size for higher volatility."],quiz:[{id:"q1",question:"Best IPO-base trigger?",options:["First day pop","Break above defined base high on strong volume","Any social trend","A red day with low volume"],correctIndex:1,explanation:"Defined structure plus demand confirmation lowers false starts."}],answers:["Break above base high with strong volume."]},{id:"adv-06",level:"Advanced",title:"High Tight Flag: Opportunity and Risk",type:"decision-lab",durationMinutes:13,focus:["breakouts"],content:["High tight flags are rare and require a very sharp prior advance plus tight consolidation.","They can produce explosive continuation, but failed attempts reverse quickly, so sizing and exits must be strict."],example:"Stock doubles in six weeks, flags tightly for 10 sessions, then breaks to highs on heavy volume.",keyTakeaways:["Rare pattern with asymmetric outcomes.","Strict risk controls are mandatory.","Demand confirmation is non-negotiable."],quiz:[{id:"q1",question:"Why is HTF advanced?",options:["No downside risk","High upside and high failure velocity","Needs no volume","Works in every regime"],correctIndex:1,explanation:"HTF setups can move fast in either direction."}],answers:["High upside with high failure velocity."]},{id:"adv-07",level:"Advanced",title:"Buy Zone and Extension Control",type:"playbook",durationMinutes:9,focus:["breakouts","portfolio"],content:["The practical buy zone is usually 0-5% above pivot. Beyond that, risk/reward worsens quickly.","If extended, wait for fresh structure rather than forcing entries from FOMO."],example:"Pivot at 100: entry at 103 is acceptable; entry at 109 is often extended unless exceptional momentum and market support exist.",keyTakeaways:["Respect 0-5% discipline.","Avoid emotional chasing.","Wait for structure when extended."],quiz:[{id:"q1",question:"Stock is +8% above pivot. Best default action?",options:["Full size now","Wait for better structure","Average up instantly","Ignore extension risk"],correctIndex:1,explanation:"Extension increases pullback risk and reduces edge."}],answers:["Wait for better structure."]},{id:"adv-08",level:"Advanced",title:"Failed Breakout Playbook",type:"case-study",durationMinutes:12,focus:["breakouts","portfolio","market"],content:["Failed breakouts often show weak closes, quick reversals below pivot, and heavy distribution.","Fast exits protect capital and reveal regime quality; repeated failures suggest reduced risk appetite in the broader market."],example:"Breakout clears pivot intraday but closes weak, then drops below pivot next session. Stop executes quickly at planned risk.",keyTakeaways:["Failure speed is a warning.","Small exits preserve optionality.","Use failures to tune exposure."],quiz:[{id:"q1",question:"Correct response to confirmed failed breakout?",options:["Argue with market","Average down","Execute risk plan","Wait indefinitely"],correctIndex:2,explanation:"Execution discipline prevents one setup from becoming a large drawdown."}],answers:["Execute the risk plan quickly."]},{id:"pro-01",level:"Pro",title:"Portfolio Construction for Growth Traders",type:"playbook",durationMinutes:15,focus:["portfolio","canslim"],content:["Construct portfolios with intentional concentration and explicit risk caps. Avoid accidental concentration by correlated names.","Blend core high-conviction positions with tactical setups, and tie cash allocation to market regime quality."],example:"Three core leaders plus four tactical positions with sector caps and cash buffer prevents one-theme blowups.",keyTakeaways:["Concentration must be intentional.","Correlation hides risk.","Cash is an active allocation tool."],quiz:[{id:"q1",question:"Hidden concentration risk example?",options:["Index plus cash","Five names in one correlated industry","One position with stop","Risk dashboard use"],correctIndex:1,explanation:"Highly correlated positions can behave like a single oversized bet."}],answers:["Too many correlated names in one industry."]},{id:"pro-02",level:"Pro",title:"Adaptive Position Sizing by Regime",type:"simulation",durationMinutes:14,focus:["portfolio","market"],content:["Risk per trade should adapt to market volatility and setup quality. Static sizing can overexpose you in unstable tape.","Reduce unit risk during chop and increase only when breakout quality and breadth improve."],example:"Unit risk cut from 1.2% to 0.6% during high volatility stabilizes drawdown and preserves mental capital.",keyTakeaways:["Sizing is regime-dependent.","Lower risk in noisy tape.","Re-risk only with evidence."],quiz:[{id:"q1",question:"Best adjustment in volatile regime?",options:["Increase size","Reduce unit risk and exposure","Remove stops","Trade only rumors"],correctIndex:1,explanation:"Smaller risk units reduce drawdown clustering."}],answers:["Reduce unit risk and total exposure."]},{id:"pro-03",level:"Pro",title:"Stop Engineering: Hard, Soft, and Time Stops",type:"case-study",durationMinutes:13,focus:["portfolio","breakouts"],content:["Hard stops cap absolute loss. Soft stops react to abnormal tape deterioration. Time stops remove stagnant trades.","Combining stop types in a predefined hierarchy improves consistency and reduces emotional overrides."],example:"Trade has hard stop at -8%, soft stop on decisive 21-day break, and time stop after 7 sessions with no progress.",keyTakeaways:["Different stops solve different risks.","Predefine hierarchy.","Time stops manage opportunity cost."],quiz:[{id:"q1",question:"Why include time stops?",options:["To exit winners","To free capital from dead trades","To avoid process","Because charts are random"],correctIndex:1,explanation:"Capital efficiency matters in portfolio management."}],answers:["To free capital from stagnant positions."]},{id:"pro-04",level:"Pro",title:"Reading a Risk Dashboard in Real Time",type:"chart",durationMinutes:11,focus:["portfolio"],content:["A useful dashboard translates data into actions: total risk %, position count, alert clustering, and concentration.","Set clear green/yellow/red thresholds with predefined responses so risk management is automatic under stress."],example:"Portfolio risk rises above 8% and multiple red alerts appear; policy triggers immediate trimming of weakest names.",keyTakeaways:["Thresholds need action plans.","Clustered alerts matter most.","Act before damage compounds."],quiz:[{id:"q1",question:"Main purpose of risk dashboard?",options:["Visual decoration","Trigger predefined actions","Replace entries","Ignore volatility"],correctIndex:1,explanation:"Dashboards should improve speed and quality of risk decisions."}],answers:["Trigger predefined risk actions."]},{id:"pro-05",level:"Pro",title:"Trading Psychology Under Pressure",type:"story",durationMinutes:12,focus:["portfolio","market"],content:["Separate outcome from process quality. Good trades can lose and bad trades can win; judge yourself by rule adherence over samples.","Use pre-commitment rules like max daily loss, cooldown after streak losses, and mandatory checklist reviews."],example:"After three losses, trader pauses, reviews checklist, skips revenge setup, and preserves capital for high-quality close setup.",keyTakeaways:["Process beats ego.","Pre-commitment reduces tilt.","Emotional control improves expectancy."],quiz:[{id:"q1",question:"Best response after emotional losses?",options:["Increase size","Pause and reset process","Remove stops","Trade constantly"],correctIndex:1,explanation:"Resetting process quality prevents compounding mistakes."}],answers:["Pause and reset process discipline."]},{id:"pro-06",level:"Pro",title:"Post-Trade Analytics and Edge Calibration",type:"decision-lab",durationMinutes:10,focus:["portfolio","breakouts","canslim"],content:["Journal outcomes by setup type, regime, and execution quality. Edge should be measured, not assumed.","Use monthly reviews to reduce low-edge patterns and scale high-confidence contexts."],example:"Data shows flat-base breakouts in confirmed uptrends outperform anticipatory entries by wide margin.",keyTakeaways:["Categorize to learn.","Calibrate from data, not memory.","Continuous improvement compounds."],quiz:[{id:"q1",question:"What should drive strategy changes?",options:["Mood","One trade","Structured review data","External noise"],correctIndex:2,explanation:"Reliable changes come from repeated evidence."}],answers:["Structured review data."]},{id:"pro-07",level:"Pro",title:"Advanced Sell Rules for Winners",type:"playbook",durationMinutes:16,focus:["portfolio","breakouts"],content:["Winning systems need sell logic: staged trims on extension, trailing rules under key averages, and exits on abnormal weakness.","Binary all-in/all-out exits often underperform staged management in trending leaders."],example:"Stock extends 10% above pivot, then shows high-volume reversal. Trader trims one-third and trails remainder under 21-day.",keyTakeaways:["Use staged exits.","Abnormal action is a sell signal.","Protecting gains is a core skill."],quiz:[{id:"q1",question:"When is trimming appropriate?",options:["Any green day","Extension plus abnormal weakness","When bored","Never trim"],correctIndex:1,explanation:"Trim decisions should be rule-based, not emotional."}],answers:["Trim on extension with abnormal weakness."]},{id:"pro-08",level:"Pro",title:"Building Your Trading Business Plan",type:"case-study",durationMinutes:18,focus:["portfolio","market","canslim","breakouts"],content:["Treat trading as an operating system with objectives, constraints, risk policy, execution standards, and review cadence.","A written plan keeps behavior stable during stress and prevents style drift after losses or wins."],example:"Plan includes max drawdown trigger that cuts size in half until recovery metrics improve.",keyTakeaways:["Operations create consistency.","Constraints protect capital.","Written rules reduce emotional drift."],quiz:[{id:"q1",question:"Core value of business plan?",options:["Predict every move","Remove all losses","Create repeatable risk-governed process","Avoid journaling"],correctIndex:2,explanation:"Durable performance comes from repeatable operations."}],answers:["A repeatable risk-governed process."]}],dailyTips:["Risk should be defined before entry, never during pain.","When breakouts keep failing, reduce exposure first.","Volume confirms whether institutions agree with price action.","Cash is a strategic position, not inactivity.","Journal mistakes by category to improve faster.","Protecting mental capital is as important as protecting cash.","Leaders in strong groups usually keep leading.","A small planned loss is a professional outcome.","Do not chase extended entries without structure.","Process consistency compounds faster than prediction skill."]}}}]);